targets.expr:
(
  100 *
  (
    sum by (service) (
      rate(http_server_requests_seconds_count{job="mini-ecommerce-actuator",uri!="/actuator/prometheus",status=~"5.."}[1m])
    )
    or on(service) (
      0 * sum by (service) (
        rate(http_server_requests_seconds_count{job="mini-ecommerce-actuator",uri!="/actuator/prometheus"}[1m])
      )
    )
  )
  / clamp_min(
    sum by (service) (
      rate(http_server_requests_seconds_count{job="mini-ecommerce-actuator",uri!="/actuator/prometheus"}[1m])
    ),
    0.001
  )
)
or on(service) (0 * max by (service) (up{job="mini-ecommerce-actuator"}))

histogram_quantile(
  0.95,
  sum by (service, le) (
    rate(http_server_requests_seconds_bucket{job="mini-ecommerce-actuator",uri!="/actuator/prometheus"}[1m])
  )
) * 1000
or on(service) (
  0 * max by (service) (up{job="mini-ecommerce-actuator"})
)

# Metrics:
# - http_server_requests_seconds_count
# Meaning:
# - Difference in service error rate versus 1 minute ago, in percentage points.
# RL use-case:
# - Reward delta signal indicating whether actions reduced service error rates.
(
  (
    100 *
    (
      sum by (service) (
        rate(http_server_requests_seconds_count{job="mini-ecommerce-actuator", uri!="/actuator/prometheus", status=~"5.."}[1m])
      )
      or on(service) (
        0 * sum by (service) (
          rate(http_server_requests_seconds_count{job="mini-ecommerce-actuator", uri!="/actuator/prometheus"}[1m])
        )
      )
    )
    /
    clamp_min(
      sum by (service) (
        rate(http_server_requests_seconds_count{job="mini-ecommerce-actuator", uri!="/actuator/prometheus"}[1m])
      ),
      0.001
    )
  )
  -
  (
    100 *
    (
      sum by (service) (
        rate(http_server_requests_seconds_count{job="mini-ecommerce-actuator", uri!="/actuator/prometheus", status=~"5.."}[1m] offset 1m)
      )
      or on(service) (
        0 * sum by (service) (
          rate(http_server_requests_seconds_count{job="mini-ecommerce-actuator", uri!="/actuator/prometheus"}[1m] offset 1m)
        )
      )
    )
    /
    clamp_min(
      sum by (service) (
        rate(http_server_requests_seconds_count{job="mini-ecommerce-actuator", uri!="/actuator/prometheus"}[1m] offset 1m)
      ),
      0.001
    )
  )
)
or on(service) (
  0 * max by (service) (up{job="mini-ecommerce-actuator"})
)

# Metrics:
# - process_cpu_usage
# - kube_pod_container_resource_requests{resource="cpu",unit="core"}
# Meaning:
# - Aggregate process CPU usage as a percentage of requested CPU budget for each service.
# RL use-case:
# - Resource saturation state signal while container-level usage and limits are unavailable.
100 *
(
  sum by (service) (
    process_cpu_usage{job="mini-ecommerce-actuator"}
  )
  /
  clamp_min(
    sum by (service) (
      label_replace(
        max by (pod, container) (
          kube_pod_container_resource_requests{
            namespace="mini-ecommerce",
            resource="cpu",
            unit="core",
            container=~"api-gateway|order-service|payment-service|product-service"
          }
        ),
        "service",
        "$1",
        "container",
        "^(.*)$"
      )
    ),
    0.001
  )
)
or on(service) (
  0 * max by (service) (up{job="mini-ecommerce-actuator"})
)

# Metrics:
# - jvm_memory_used_bytes
# - kube_pod_container_resource_requests{resource="memory",unit="byte"}
# Meaning:
# - JVM memory usage as a percentage of requested memory budget for each service.
# RL use-case:
# - Memory pressure state signal while container-level working set and limits are unavailable.
100 *
(
  sum by (service) (
    jvm_memory_used_bytes{job="mini-ecommerce-actuator"}
  )
  /
  clamp_min(
    sum by (service) (
      label_replace(
        max by (pod, container) (
          kube_pod_container_resource_requests{
            namespace="mini-ecommerce",
            resource="memory",
            unit="byte",
            container=~"api-gateway|order-service|payment-service|product-service"
          }
        ),
        "service",
        "$1",
        "container",
        "^(.*)$"
      )
    ),
    1
  )
)
or on(service) (
  0 * max by (service) (up{job="mini-ecommerce-actuator"})
)
